-- V20260606_001__MigrateCommonCodes.sql
-- [자동생성: _data/_gen-migration.mjs] 공통코드 그룹ID/값ID 신규 체계 재적재.
-- 멱등: 영향 그룹 전체 DELETE 후 재INSERT. FST_ENR_USID='MIGRATION' 표식.
-- 신규측 전체 컬럼(임계금액 CO_CDVA_NM, 정렬 C_SQN_SNO, 계층 HRK 포함) 보존.

-- 1) 백업 (이미 있으면 건너뜀)
DECLARE v NUMBER;
BEGIN
  SELECT COUNT(*) INTO v FROM USER_TABLES WHERE TABLE_NAME='TPRMPP_CCODEM_BAK_20260606';
  IF v=0 THEN
    EXECUTE IMMEDIATE 'CREATE TABLE ITPAPP.TPRMPP_CCODEM_BAK_20260606 AS SELECT * FROM ITPAPP.TPRMPP_CCODEM';
  END IF;
END;
/

-- 2) 영향 old+new 그룹 제거(재실행 대비 클린 슬레이트)
DELETE FROM ITPAPP.TPRMPP_CCODEM WHERE CO_C_ID IN ('ABUS_C','ABUS_TC','APF_PRG_STS_C','APF_STS','BG_RQS','BG_UNT_ABUS_C','BLB_TC','BZ_DTT','CKG_ITM_C','CST_TP_TC','CUR','CUR_C','DCD_STS','DFR_CLE','DFR_CLE_C','DUP_AMT','DUP_IOE','EDRT_CPIT','EDRT_MNGC','EXE_PTT_YN','INFM_SVC','INFM_SVC_TC','IOE','IOE_C','IT_MNGC_TP','IT_PTL_EDRT_TC','IT_PTL_RPR_STS_TC','IT_PTL_TCHN_TP_TC','IT_PTL_TMN_KD_TC','IT_PTL_TMN_SVC_TC','KPN_TC','MN_USR','NAC_TP','PRIT_C','PRJ_PUL_PTT','PRJ_TP','PUL_DTT','RPR_STS','SD','SD_TC','SYS_PVC','SYS_RQC','TCHN_TP','TMN_KD','TMN_MAGR','TMN_USG','TMN_YN');

-- 3) 신규 목표 상태 재적재 (153행)

-- 4) 변경 스냅샷(감사) — CCODEL
SELECT ITPAPP.SEQ_CCODEL.NEXTVAL, CO_C_ID, CDVA_ID, STT_DTM, END_DTM, CO_CDVA_NM, CO_C_NM, CDVA_NM, C_SQN_SNO, HRK_CDVA_ID, 'Y', SYSDATE, 'MIGRATION', 'N'
FROM ITPAPP.TPRMPP_CCODEM WHERE FST_ENR_USID='MIGRATION';

COMMIT;
